  W=P;
  long total=st.st_size/4;
  long o=0;
  printf("total %lu\n",total);
  printf("wte %lu %f %f\n",o,G(o),G(o+767));o+=50257768LL;
  printf("wpe %lu %f %f\n",o,G(o),G(o+767));o+=1024768LL;
  long blk=2768+7682304+2304+768768+768+2768+7683072+3072+3072768+768;
  printf("blk %lu\n",blk);
  for(int h=0;h<12;h++){
    printf("h%d ln1g %lu %f ln1b %lu %f\n",h,o,G(o),o+768,G(o+768));o+=2768;
    printf("h%d caw %lu cab %lu cpw %lu cpb %lu\n",h,o,o+7682304,o+7682304+2304,o+7682304+2304+768768);
    o+=7682304+2304+768768+768;
    printf("h%d ln2g %lu ln2b %lu\n",h,o,o+768);o+=2768;
    printf("h%d fcw %lu fcb %lu pw %lu pb %lu\n",h,o,o+7683072,o+7683072+3072,o+7683072+3072+3072768);
    o+=7683072+3072+3072768+768;
  }
  printf("lnfg %lu %f lnfb %lu %f\n",o,G(o),o+768,G(o+768));o+=2768;
  printf("end %lu\n",o);
