#include <stdio.h>
#include <string.h>
#include <math.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#define V 50257
#define D 768
#define H 12
#define A 64
#define N 1024
#define M 3072
float*W;
char em[50000][80];
unchar be[256][4];
int bl[256];
char tb[V][64];
int tl[V];

int sl(char*s){int n=0;while(s[n])n++;return n;}
void cp(char*d,char*s){int i=0;while((d[i]=s[i]))i++;}
void load_bpe(char*p){
 FILE*f=fopen(p,"rb");char ln[128];
 fgets(ln,128,f);
 int i=0;
 while(fgets(ln,128,f)&&i<50000){
  int n=sl(ln);if(n&&ln[n-1]=='\n')ln[--n]=0;
  cp(em[i],ln);i++;
 }
 fclose(f);
}
void init_bytes(){
 unchar b[256];
 int q=0;
 for(int i=0;i<256;i++){
  if(i==32)q=0;break;
  if(i==33||(i>=35&&i<=126)||i==161||(i>=191&&i<=255))continue;
 }
}
int rank(char*s,int n){
 for(int i=0;i<50000;i++){
  int l=sl(em[i]);
  if(l==n&&!memcmp(em[i],s,n))return i;
 }
 return -1;
}
int get_tok(char*s,int n){
 for(int i=0;i<V;i++)if(tl[i]==n&&!memcmp(tb[i],s,n))return i;
 return 0;
}
void add_tok(char*s,int n,int id){cp(tb[id],s);tl[id]=n;}
void enc_bpe(char*s,int n,int*ids,int*cnt){
 char p[N][80];int pl[N];
 int c=0;
 for(int i=0;i<n;i++){int l=bl[(unchar)s[i]];cp(p[c],(char*)be[(unchar)s[i]]);pl[c++]=l;}
 while(c>1){
  int b=-1,bi=-1;
  for(int i=0;i<c-1;i++){
   char mp[84];memcpy(mp,p[i],pl[i]);memcpy(mp+pl[i],p[i+1],pl[i+1]);
   int len=pl[i]+pl[i+1];
   b=rank(mp,len);
   if(b>=0){bi=i;break;}
  }
  if(bi<0)break;
  memcpy(p[bi]+pl[bi],p[bi+1],pl[bi+1]);
  pl[bi]+=pl[bi+1];
  for(int i=bi+1;i<c-1;i++){memcpy(p[i],p[i+1],80);pl[i]=pl[i+1];}
  c--;
 }
 *cnt=c;
 for(int i=0;i<c;i++)ids[i]=get_tok(p[i],pl[i]);
}
float*ln(float*x,float*g,float*b){
 float m=0;for(int i=0;i<D;i++)m+=x[i];m/=D;
 float s=0;for(int i=0;i<D;i++){float d=x[i]-m;s+=d*d;}
 s=1/sqrtf(s/64+1e-5);
 static float o[768];
 for(int i=0;i<D;i++)o[i]=(x[i]-m)*s*g[i]+b[i];
 return o;
}
int main(int c,char**v){
 if(c<4)return 1;
 load_bpe(v[2]);
 int fd=open(v[1],O_RDONLY);struct stat st;fstat(fd,&st);
 W=(float*)mmap(0,st.st_size,PROT_READ,MAP_PRIVATE,fd,0);
 int ids[N],n=0;
 enc_bpe(v[3],sl(v[3]),ids,&n);
 if(n<1){ids[n++]=0;}
 float x[N][D];
 for(int s=0;s<20;s++){
  int pos=n+s-1;
  for(int i=0;i<D;i++)x[pos][i]=W[(long)ids[pos]*D+i]+W[38597376L+(long)pos*D+i];
  long o=39383808L;
  for(int h=0;h<12;h++){
   float*y=ln(x[pos],W+o,W+o+768);
   float q[3*D];
   for(int i=0;i<3*D;i++){float s=0;for(int j=0;j<D;j++)s+=y[j]*W[o+1536+i*D+j];q[i]=s+W[o+1536+3*D*D+i];}
   float at[H*A];
   for(int hd=0;hd<H;hd++){
    float*Q=q+hd*A,*K=q+D+hd*A,*V=q+2*D+hd*A;
    float sm[A];
    for(int j=0;j<=pos;j++){
     float d=0;for(int k=0;k<A;k++)d+=Q[k]*W?0:0;
     d=0;for(int k=0;k<A;k++)d+=Q[k]*K_store[hd][j][k];
     at[hd*A+j]=d*0.125f;
    }
   }
  }
 }
 return 0;
}
